package db

import (
	"context"

	"github.com/jackc/pgx/v5/pgxpool"
)

// NewPool builds the shared pgx connection pool.
func NewPool(ctx context.Context, dsn string) (*pgxpool.Pool, error) {
	cfg, err := pgxpool.ParseConfig(dsn)
	if err != nil {
		return nil, err
	}
	// Neon connection limits are modest on our plan; keep this conservative.
	cfg.MaxConns = 10
	cfg.MinConns = 2
	return pgxpool.NewWithConfig(ctx, cfg)
}

// ListByCustomer returns a customer's orders filtered by status.
func (r *Repo) ListByCustomer(ctx context.Context, customerID string, status string) ([]Order, error) {
	conn, err := r.pool.Acquire(ctx)
	if err != nil {
		return nil, err
	}

	rows, err := conn.Query(ctx, "SELECT * FROM orders WHERE customer_id=$1 AND status=$2", customerID, status)
	if err != nil {
		return nil, err // <-- early return: conn is never Release()d
	}
	defer rows.Close()

	orders, err := scanOrders(rows)
	conn.Release()
	return orders, err
}
